const initialDeploymentCost = Number(inputs.initialDeploymentCost);
const reactorElectricalPower = Number(inputs.reactorElectricalPower);
const reactorCapacityFactor = Number(inputs.reactorCapacityFactor);
const reactorOperationalLife = Number(inputs.reactorOperationalLife);
const annualOMCostReactor = Number(inputs.annualOMCostReactor);
const fuelCostPerMWh = Number(inputs.fuelCostPerMWh);
const conventionalEnergyCostMWh = Number(inputs.conventionalEnergyCostMWh);
const conventionalOMCostMWh = Number(inputs.conventionalOMCostMWh);

if (isNaN(initialDeploymentCost) || initialDeploymentCost < 0) return { error: 'Initial Deployment Cost must be a non-negative number.' };
if (isNaN(reactorElectricalPower) || reactorElectricalPower <= 0) return { error: 'Reactor Electrical Power Output must be a positive number.' };
if (isNaN(reactorCapacityFactor) || reactorCapacityFactor < 0 || reactorCapacityFactor > 100) return { error: 'Reactor Capacity Factor must be between 0 and 100.' };
if (isNaN(reactorOperationalLife) || reactorOperationalLife <= 0) return { error: 'Reactor Operational Lifespan must be a positive number.' };
if (isNaN(annualOMCostReactor) || annualOMCostReactor < 0) return { error: 'Annual O&M Cost must be a non-negative number.' };
if (isNaN(fuelCostPerMWh) || fuelCostPerMWh < 0) return { error: 'Micro-Reactor Fuel Cost per MWh must be a non-negative number.' };
if (isNaN(conventionalEnergyCostMWh) || conventionalEnergyCostMWh < 0) return { error: 'Alternative Energy Cost per MWh must be a non-negative number.' };
if (isNaN(conventionalOMCostMWh) || conventionalOMCostMWh < 0) return { error: 'Alternative System O&M Cost per MWh must be a non-negative number.' };

const HOURS_PER_YEAR = 8760;

// 1. Convert Capacity Factor to decimal
const cfDecimal = reactorCapacityFactor / 100;

// 2. Calculate Annual Energy Generation (MWh/year)
const annualEnergyMWh = reactorElectricalPower * HOURS_PER_YEAR * cfDecimal;

// 3. Calculate Total Reactor Energy Generated over its operational life (MWh)
const totalReactorEnergyMWh = annualEnergyMWh * reactorOperationalLife;

// 4. Calculate Total Lifetime Operational & Maintenance Cost for the micro-reactor
const totalOMCostReactor = annualOMCostReactor * reactorOperationalLife;

// 5. Calculate Total Lifetime Fuel Cost for the micro-reactor
const totalFuelCostReactor = fuelCostPerMWh * totalReactorEnergyMWh;

// 6. Calculate Total Reactor Lifetime Cost
const totalReactorLifetimeCost = initialDeploymentCost + totalOMCostReactor + totalFuelCostReactor;

// 7. Calculate Micro-Reactor Levelized Cost of Electricity (LCOE)
const reactorLCOE = totalReactorEnergyMWh > 0 ? totalReactorLifetimeCost / totalReactorEnergyMWh : Infinity;

// 8. Calculate Equivalent Conventional Lifetime Cost
const equivalentConventionalCost = (conventionalEnergyCostMWh + conventionalOMCostMWh) * totalReactorEnergyMWh;

// 9. Calculate Net Savings (or Loss) from deploying the micro-reactor compared to conventional sources
const netSavings = equivalentConventionalCost - totalReactorLifetimeCost;

// 10. Calculate Return on Investment (ROI)
let roi = 0;
if (initialDeploymentCost > 0) {
    roi = (netSavings / initialDeploymentCost) * 100;
} else if (netSavings > 0) {
    roi = Infinity; // Infinite ROI if no initial cost and there are savings
}

// 11. Calculate Simple Payback Period
const annualConventionalCost = (conventionalEnergyCostMWh + conventionalOMCostMWh) * annualEnergyMWh;
const annualReactorOperatingCost = annualOMCostReactor + (fuelCostPerMWh * annualEnergyMWh);
const annualSavings = annualConventionalCost - annualReactorOperatingCost;

let paybackPeriod = Infinity; // Default to Infinity (not achievable)
if (initialDeploymentCost === 0) {
    paybackPeriod = 0; // If no initial cost, payback is immediate
} else if (annualSavings > 0) {
    paybackPeriod = initialDeploymentCost / annualSavings;
    // If payback period exceeds operational life, it's not achieved within the desired timeframe
    if (paybackPeriod > reactorOperationalLife) {
        paybackPeriod = Infinity;
    }
}

return {
    totalReactorEnergyMWh,
    totalReactorLifetimeCost,
    reactorLCOE,
    equivalentConventionalCost,
    netSavings,
    roi,
    paybackPeriod
};
